290→function sliderThumbCenterPercent(valuePct: number, trackPx: number, thumbPx: number): string {
291→  const clamped = Math.max(0, Math.min(100, valuePct));
292→  const min = thumbPx * 0.5;
293→  const max = Math.max(min, trackPx - thumbPx * 0.5);
294→  const center = min + ((max - min) * clamped) / 100;
295→  return `${(center / trackPx) * 100}%`;
296→}
