300→  const min = trackTopPx + thumbPx * 0.5;
301→  const max = Math.max(min, trackTopPx + trackHeightPx - thumbPx * 0.5);
302→  const center = min + ((max - min) * clamped) / 100;
303→  return `${center}px`;
