386→async function loadBlpDataUrl(path: string): Promise<string> {
387→  const cached = iconDataUrlCache.get(path);
388→  if (cached) return cached;
389→
390→  const promise = (async () => {
391→    const res = await fetch(path);
392→    if (!res.ok) throw new Error(`Failed to fetch icon ${path}`);
393→    const ab = await res.arrayBuffer();
394→    const blp = decodeBLP(ab);
395→    const img = getBLPImageData(blp, 0);
396→    const pixelData = new Uint8ClampedArray(img.data);
397→    if (shouldForceOpaqueOnZeroAlpha(path)) {
398→      let allAlphaZero = true;
399→      for (let i = 3; i < pixelData.length; i += 4) {
400→        if (pixelData[i] !== 0) {
401→          allAlphaZero = false;
402→          break;
403→        }
404→      }
405→      if (allAlphaZero) {
406→        for (let i = 3; i < pixelData.length; i += 4) {
407→          pixelData[i] = 255;
408→        }
409→      }
410→    }
411→    if (shouldApplyBlackColorKey(path)) {
412→      for (let i = 0; i < pixelData.length; i += 4) {
413→        const r = pixelData[i];
414→        const g = pixelData[i + 1];
415→        const b = pixelData[i + 2];
416→        const a = pixelData[i + 3];
417→        if (a > 224 && r <= 10 && g <= 10 && b <= 10) {
418→          pixelData[i + 3] = 0;
419→        }
420→      }
421→    }
422→    const canvas = document.createElement('canvas');
423→    canvas.width = img.width;
424→    canvas.height = img.height;
425→    const ctx = canvas.getContext('2d');
426→    if (!ctx) throw new Error(`Failed to decode icon ${path}`);
427→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
428→    return canvas.toDataURL('image/png');
429→  })();
430→
431→  iconDataUrlCache.set(path, promise);
432→  return promise;
433→}
