483→async function cropImageRegionToDataUrl(src: string, x: number, y: number, width: number, height: number): Promise<string> {
484→  const key = `${src}|${x}|${y}|${width}|${height}`;
485→  const cached = croppedImageRegionCache.get(key);
486→  if (cached) return cached;
487→
488→  const promise = (async () => {
489→    const img = await loadDataUrlImage(src);
490→    const sx = Math.max(0, Math.min(img.width - 1, Math.floor(x)));
491→    const sy = Math.max(0, Math.min(img.height - 1, Math.floor(y)));
492→    const sw = Math.max(1, Math.min(img.width - sx, Math.floor(width)));
493→    const sh = Math.max(1, Math.min(img.height - sy, Math.floor(height)));
494→    const cropCanvas = document.createElement('canvas');
495→    cropCanvas.width = sw;
496→    cropCanvas.height = sh;
497→    const cropCtx = cropCanvas.getContext('2d');
498→    if (!cropCtx) return src;
499→    cropCtx.clearRect(0, 0, sw, sh);

500→    cropCtx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
501→    return cropCanvas.toDataURL('image/png');
502→  })();
503→
504→  croppedImageRegionCache.set(key, promise);
505→  return promise;
506→}
