508→async function loadRaceCursorFrameDataUrl(race: Race): Promise<string> {
509→  const cached = cursorFrameDataUrlCache.get(race);
510→  if (cached) return cached;
511→
512→  const promise = (async () => {
513→    const atlasDataUrl = await loadBlpDataUrl(`/cursor/${race}Cursor.blp`);
514→    const atlas = await loadDataUrlImage(atlasDataUrl);
515→    const columns = 8;
516→    const rows = 4;
517→    const frameW = Math.max(1, Math.floor(atlas.width / columns));
518→    const frameH = Math.max(1, Math.floor(atlas.height / rows));
519→    const canvas = document.createElement('canvas');
520→    canvas.width = frameW;
521→    canvas.height = frameH;
522→    const ctx = canvas.getContext('2d');
523→    if (!ctx) return atlasDataUrl;
524→    ctx.imageSmoothingEnabled = false;
525→    ctx.clearRect(0, 0, frameW, frameH);
526→    ctx.drawImage(atlas, 0, 0, frameW, frameH, 0, 0, frameW, frameH);
527→    return canvas.toDataURL('image/png');
528→  })();
529→
530→  cursorFrameDataUrlCache.set(race, promise);
531→  return promise;
532→}
