626→interface NineSliceTemplateOptions {
627→  cornerPx: number;
628→  insetPx: number;
629→  tileBackground?: boolean;
630→  tileHorizontalEdges?: boolean;
631→  opaqueBaseFill?: string | null;
632→  fillCornerMaxPx?: number;
