782→const additiveSrcColorScratchCanvas = document.createElement('canvas');
783→
784→function compositeSrcColorAdditive(
785→  dstCtx: CanvasRenderingContext2D,
786→  pxW: number,
787→  pxH: number,
788→  dpr: number,
789→  cssW: number,
790→  cssH: number,
791→  drawSource: (ctx: CanvasRenderingContext2D) => void,
792→) {
793→  if (additiveSrcColorScratchCanvas.width !== pxW || additiveSrcColorScratchCanvas.height !== pxH) {
794→    additiveSrcColorScratchCanvas.width = pxW;
795→    additiveSrcColorScratchCanvas.height = pxH;
796→  }
797→
798→  const srcCtx = additiveSrcColorScratchCanvas.getContext('2d');
799→  if (!srcCtx) return;

 800→  srcCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
 801→  srcCtx.clearRect(0, 0, cssW, cssH);
 802→  srcCtx.imageSmoothingEnabled = true;
 803→  drawSource(srcCtx);
 804→
 805→  const srcImage = srcCtx.getImageData(0, 0, pxW, pxH);
 806→  const dstImage = dstCtx.getImageData(0, 0, pxW, pxH);
 807→  const src = srcImage.data;
 808→  const dst = dstImage.data;
 809→
 810→  // Warcraft III Additive layer mode maps to GL blendFunc(SRC_COLOR, ONE).
 811→  for (let i = 0; i < dst.length; i += 4) {
 812→    const srcR = src[i] / 255;
 813→    const srcG = src[i + 1] / 255;
 814→    const srcB = src[i + 2] / 255;
 815→    const srcA = src[i + 3] / 255;
 816→    dst[i] = Math.min(255, dst[i] + Math.round(srcR * srcR * 255));
 817→    dst[i + 1] = Math.min(255, dst[i + 1] + Math.round(srcG * srcG * 255));
 818→    dst[i + 2] = Math.min(255, dst[i + 2] + Math.round(srcB * srcB * 255));
 819→    dst[i + 3] = Math.min(255, dst[i + 3] + Math.round(srcA * srcA * 255));
 820→  }
 821→
 822→  dstCtx.putImageData(dstImage, 0, 0);
 823→}
 824→
 825→function drawSimpleStatusBarToCanvas(
 826→  canvas: HTMLCanvasElement,
 827→  fillImg: HTMLImageElement,
 828→  borderImg: HTMLImageElement,
 829→  highlightImg: HTMLImageElement | null,
 830→  valuePct: number,
 831→  fillProfile: StatusBarFillProfile,
 832→  fillTint?: string,
 833→) {
 834→  const rect = canvas.getBoundingClientRect();
 835→  const cssW = Math.max(1, rect.width);
 836→  const cssH = Math.max(1, rect.height);
 837→  const dpr = window.devicePixelRatio || 1;
 838→  const pxW = Math.max(1, Math.round(cssW * dpr));
 839→  const pxH = Math.max(1, Math.round(cssH * dpr));
 840→  if (canvas.width !== pxW || canvas.height !== pxH) {
 841→    canvas.width = pxW;
 842→    canvas.height = pxH;
 843→  }
 844→
 845→  const ctx = canvas.getContext('2d');
 846→  if (!ctx) return;
 847→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
 848→  ctx.clearRect(0, 0, cssW, cssH);
 849→  ctx.imageSmoothingEnabled = true;
 850→
 851→  const fillW = cssW * modelBarFillRatio(valuePct, fillProfile);
 852→  if (fillW > 0) {
 853→    ctx.drawImage(fillImg, 0, 0, fillImg.width, fillImg.height, 0, 0, fillW, cssH);
 854→    if (fillTint) {
 855→      ctx.save();
 856→      ctx.globalCompositeOperation = 'multiply';
 857→      ctx.fillStyle = fillTint;
 858→      ctx.fillRect(0, 0, fillW, cssH);
 859→      ctx.restore();
 860→    }
 861→  }
 862→
 863→  if (highlightImg) {
 864→    compositeSrcColorAdditive(ctx, pxW, pxH, dpr, cssW, cssH, (srcCtx) => {
 865→      srcCtx.drawImage(highlightImg, 0, 0, highlightImg.width, highlightImg.height, 0, 0, cssW, cssH);
 866→    });
 867→  }
 868→
 869→  ctx.drawImage(borderImg, 0, 0, borderImg.width, borderImg.height, 0, 0, cssW, cssH);
 870→}
