                description="Vertical scroll track with up/down arrows and a draggable knob, from the login and menu screens."
              >
                <div className="button-preview-row">
                  <div className="button-preview-col">
                    <div className="glue-scrollbar-demo">
                      <button type="button" className="glue-scroll-arrow" aria-label="Scroll up" onClick={() => bumpGlueScroll(-8)}>
                        <img src={glueScrollUpArrowUrl} alt="" />
                      </button>
                      <div className="glue-scroll-track">
                        <canvas ref={glueScrollBarCanvasRef} className="glue-scroll-track-canvas" />
                        <div
                          className="glue-scroll-thumb"
                          style={{
                            backgroundImage: `url("${glueScrollKnobUrl}")`,
                            top: glueScrollThumbTop,
                          }}
                        />
                        <input
                          type="range"
                          min="0"
                          max="100"
                          value={glueScrollValue}
                          aria-label="Glue scrollbar position"
                          onChange={(event) => setGlueScrollValue(Number(event.currentTarget.value))}
                        />
                      </div>
                      <button type="button" className="glue-scroll-arrow" aria-label="Scroll down" onClick={() => bumpGlueScroll(8)}>
                        <img src={glueScrollDownArrowUrl} alt="" />
                      </button>
                    </div>
                    <div className="button-state-label">Interactive</div>
                  </div>
                  <div className="button-preview-col">
                    <div className="glue-scrollbar-demo glue-scrollbar-demo--disabled">
                      <button type="button" className="glue-scroll-arrow" disabled>
                        <img src={glueScrollUpArrowUrl} alt="" />
                      </button>
                      <div className="glue-scroll-track">
                        <canvas ref={glueScrollBarDisabledCanvasRef} className="glue-scroll-track-canvas" />
                        <div
                          className="glue-scroll-thumb"
                          style={{
                            backgroundImage: `url("${glueScrollKnobDisabledUrl || glueScrollKnobUrl}")`,
                            top: glueScrollDisabledThumbTop,
                          }}
                        />
                      </div>
                      <button type="button" className="glue-scroll-arrow" disabled>
                        <img src={glueScrollDownArrowUrl} alt="" />
                      </button>
                    </div>
                    <div className="button-state-label">Disabled</div>
                  </div>
                </div>
              </ButtonShowcaseSection>

              <ButtonShowcaseSection
                title="Text Area"
                description="Scrollable text panel with a decorated border and attached scroll thumb, used in the options menu."
              >
                <div className="button-preview-row button-preview-row--textarea">
                  <div className="button-preview-col button-preview-col--textarea">
                    <div className="esc-textarea-demo">
                      <div className="esc-textarea-shell">
                        <canvas ref={escTextAreaCanvasRef} className="esc-textarea-canvas" />
                        <div className="esc-textarea-mask">
                          <div
                            className="esc-textarea-content"
                            style={{
                              transform: `translateY(-${escTextAreaOffsetPx}px)`,
                              lineHeight: `${escTextAreaLineHeightPx}px`,
                            }}
                          >
                            {escTextAreaLines.map((line, i) => (
                              <div key={i}>{line}</div>
                            ))}
                          </div>
                        </div>
                      </div>
                      <div className="esc-textarea-scroll">
                        <canvas ref={escTextAreaScrollCanvasRef} className="esc-textarea-scroll-canvas" />
                        <div
                          className="esc-textarea-scroll-thumb"
                          style={{
                            backgroundImage: `url("${sliderKnobUrl}")`,
                            top: escTextAreaScrollThumbTop,
                          }}
                        />
                        <input
                          type="range"
                          min="0"
                          max="100"
                          value={escTextScrollValue}
                          aria-label="Esc text area scroll position"
                          onChange={(event) => setEscTextScrollValue(Number(event.currentTarget.value))}
                        />
                      </div>
                    </div>
                    <div className="button-state-label">Interactive Log Panel</div>
                  </div>
                </div>
              </ButtonShowcaseSection>

              <ButtonShowcaseSection
                title="List Box"
                description="Bordered scrollable list from the menu screens, pairing a text input container with a scrollbar."
              >
                <div className="button-preview-row">
                  <div className="button-preview-col">
                    <div className="wc3-listbox-demo">
                      <div className="wc3-listbox-shell">
                        <canvas ref={glueListBoxCanvasRef} className="wc3-listbox-canvas" />
                        <div className="wc3-listbox-mask">
                          <div
                            className="wc3-listbox-items"
                            style={{
                              transform: `translateY(-${glueListBoxOffsetPx}px)`,
                              lineHeight: `${glueListBoxLineHeightPx}px`,
                            }}
                          >
                            {glueListBoxItems.map((item) => (
                              <button
                                key={item}
                                type="button"
                                className={`wc3-listbox-item${listBoxSelected === item ? ' wc3-listbox-item--selected' : ''}`}
                                onClick={() => setListBoxSelected(item)}
                              >
                                {item}
                              </button>
                            ))}
                          </div>
                        </div>
                      </div>
                      <div className="wc3-listbox-scrollbar">
                        <button type="button" className="wc3-listbox-scroll-arrow" aria-label="Listbox scroll up" onClick={() => bumpListBoxScroll(-10)}>
                          <img src={glueScrollUpArrowUrl} alt="" />
                        </button>
                        <div className="wc3-listbox-scroll">
                          <canvas ref={glueListBoxScrollCanvasRef} className="wc3-listbox-scroll-canvas" />
                          <div
                            className="wc3-listbox-scroll-thumb"
                            style={{
                              backgroundImage: `url("${glueScrollKnobUrl}")`,
                              top: glueListScrollThumbTop,
                            }}
                          />
                          <input
                            type="range"
                            min="0"
                            max="100"
                            value={listBoxScrollValue}
                            aria-label="Listbox scroll position"
                            onChange={(event) => setListBoxScrollValue(Number(event.currentTarget.value))}
                          />
                        </div>
                        <button type="button" className="wc3-listbox-scroll-arrow" aria-label="Listbox scroll down" onClick={() => bumpListBoxScroll(10)}>
                          <img src={glueScrollDownArrowUrl} alt="" />
                        </button>
                      </div>
                    </div>
                    <div className="button-state-label">Selectable Items</div>
                  </div>
                </div>
              </ButtonShowcaseSection>
            </div>
            </ControlsSection>
          </div>
          <div className="showcase-flow-item showcase-flow-item--resource-counters">
            <ResourceCounterSection>
              <div className="button-preview-row" style={{ justifyContent: 'space-evenly' }}>
                {/* Gold */}
                <div className="button-preview-col">
                  <div className="resource-counter">
                    <img src={goldIconUrl} alt="Gold" />
                    <span>{goldValue}</span>
                  </div>
                  <div className="button-state-label">Gold</div>
                </div>
                {/* Lumber */}
                <div className="button-preview-col">
                  <div className="resource-counter">
                    <img src={lumberIconUrl} alt="Lumber" />
                    <span>{lumberValue}</span>
                  </div>
                  <div className="button-state-label">Lumber</div>
                </div>
                {/* Supply */}
                <div className="button-preview-col">
                  <div className="resource-counter">
                    <img src={supplyDrumstickUrl} alt="Supply" />
                    <span>{supplyUsed}/{supplyCap}</span>
                  </div>
                  <div className="button-state-label">Supply</div>
                </div>
                {/* Upkeep */}
                <div className="button-preview-col">
                  <div className="resource-counter" style={{ color: upkeepLabel.color }}>
                    <span>{upkeepLabel.text}</span>
                  </div>
                  <div className="button-state-label">Upkeep</div>
                </div>
              </div>
            </ResourceCounterSection>
          </div>
          <div className="showcase-flow-item showcase-flow-item--command-card">
            <CommandCardSection
              iconUrls={blademasterCmdIconUrls}
              disabledIconUrls={blademasterCmdDisabledIconUrls}
              highlightUrl={cmdBtnHighlightUrl}
              groupBorderUrl={cmdGroupBorderUrl}
              subgroupBgUrl={cmdSubgroupBgUrl}
            />
          </div>
          <div className="showcase-flow-item showcase-flow-item--unit-queue">
            <UnitQueueSection
              backdropUrl={unitQueueBorderUrl}
              iconUrl={unitQueuePeonIconUrl}
            />
          </div>
          <div className="showcase-flow-item showcase-flow-item--tooltip">
            <TooltipSection
              backgroundUrl={tooltipBgUrl}
              borderImageUrl={tooltipBorderImageUrl}
              goldIconUrl={tooltipGoldIconUrl}
              lumberIconUrl={tooltipLumberIconUrl}
              supplyIconUrl={tooltipSupplyIconUrl}
            />
          </div>
          <div className="showcase-flow-item showcase-flow-item--portrait">
            <PortraitFrameSection />
          </div>
          <div className="showcase-flow-item showcase-flow-item--bars">
            <BarsSection>
              <div className="button-showcase-grid">
                <ButtonShowcaseSection
                  title="Health Bar"
                  description="Green unit health bar from the in-game portrait panel with highlight and edge overlays."
                >
                  <div className="wc3-bar wc3-bar--unit wc3-bar--health">
                    <canvas ref={healthBarCanvasRef} className="wc3-bar-canvas" />
                    <div className="wc3-bar-text">{`${Math.round((healthBarPct * 650) / 100)} / 650`}</div>
                  </div>
                  <div className="button-state-label">Model-Style</div>
                </ButtonShowcaseSection>

                <ButtonShowcaseSection
                  title="Mana Bar"
                  description="Blue mana bar sharing the same highlight and edge overlays as the health bar."
                >
                  <div className="wc3-bar wc3-bar--unit wc3-bar--mana">
                    <canvas ref={manaBarCanvasRef} className="wc3-bar-canvas" />
                    <div className="wc3-bar-text">{`${Math.round((manaBarPct * 300) / 100)} / 300`}</div>
                  </div>
                  <div className="button-state-label">Model-Style</div>
                </ButtonShowcaseSection>

                <ButtonShowcaseSection
                  title="XP Bar"
                  description="Hero experience bar with a purple fill and the classic XP border frame."
                >
                  <div className="wc3-bar wc3-bar--compact wc3-bar--xp">
                    <canvas ref={xpBarCanvasRef} className="wc3-bar-canvas" />
                    <div className="wc3-bar-text">{`Level 3 · ${Math.floor(xpBarPct)}%`}</div>
                  </div>
                  <div className="button-state-label">Hero XP</div>
                </ButtonShowcaseSection>

                <ButtonShowcaseSection
                  title="Progress Bar"
                  description="Generic timed progress indicator for training, upgrades, and other queued actions."
                >
                  <div className="wc3-bar wc3-bar--compact wc3-bar--progress">
                    <canvas ref={progressBarCanvasRef} className="wc3-bar-canvas" />
                    <div className="wc3-bar-text">{`${Math.floor(progressBarPct)}%`}</div>
                  </div>
                  <div className="button-state-label">Timer</div>
                </ButtonShowcaseSection>

                <ButtonShowcaseSection
                  title="Build Progress"
                  description="Construction progress indicator with its own fill and border textures."
                >
                  <div className="wc3-bar wc3-bar--compact wc3-bar--build">
                    <canvas ref={buildProgressCanvasRef} className="wc3-bar-canvas" />
                    <div className="wc3-bar-text">{`${Math.floor(buildBarPct)}%`}</div>
                  </div>
                  <div className="button-state-label">Build Time</div>
                </ButtonShowcaseSection>

                <ButtonShowcaseSection
                  title="Loading Screen Bar"
                  description="Full-width loading bar from the map load screen with a tiled track, glass border, and progress glow."
                >
                  <div className="loading-preview">
                    <div className="loading-bar-composite">
                      <div
                        className="lb-track"
                        style={{
                          left: `${loadingTrackInsetLeftPct}%`,
                          right: `${loadingTrackInsetRightPct}%`,
                          top: `${loadingTrackInsetTopPct}%`,
                          bottom: `${loadingTrackInsetBottomPct}%`,
                        }}
                      >
                        <div className="lb-bg" style={{ backgroundImage: `url("${loadingBgUrl}")` }} />
                        <div
                          className="lb-fill"
                          style={{
                            backgroundImage: `url("${loadingFillUrl}")`,
                            width: `${loadingFillPct}%`,
                          }}
                        />
                      </div>
                      <img className="lb-border" src={loadingBorderUrl} alt="" />
                      <img className="lb-glass" src={loadingGlassUrl} alt="" />
                      <img
                        className="lb-glow"
                        src={loadingGlowUrl}
                        alt=""
                        style={{
                          left: `${loadingGlowInsetLeftPct}%`,
                          top: `${loadingGlowInsetTopPct}%`,
                          bottom: `${loadingGlowInsetBottomPct}%`,
                          width: `${loadingGlowWidthPct}%`,
                          opacity: `${loadingGlowOpacity}`,
                        }}
                      />
                      <div className="lb-text">{`${Math.floor(loadingBarPct)}%`}</div>
                    </div>
                  </div>
                  <div className="button-state-label">Model layering and geometry</div>
                </ButtonShowcaseSection>
              </div>
            </BarsSection>
          </div>
          <div className="showcase-flow-item showcase-flow-item--borders">
            <BordersSection loadBlpDataUrl={loadBlpDataUrl} />
          </div>
          <div className="showcase-flow-item showcase-flow-item--tokens">
            <DesignTokensSection borderAtlasUrls={factionBorderUrls} />
          </div>
          <div className="showcase-flow-item showcase-flow-item--a11y">
            <AccessibilitySection />
          </div>
          <div className="showcase-flow-item showcase-flow-item--bundle">
            <BundleSizeSection buildFillUrl={buildFillUrl} buildBorderUrl={buildBorderUrl} />
          </div>
          <div className="showcase-flow-item showcase-flow-item--faq">
            <FAQSection />
          </div>
          <div className="showcase-flow-item showcase-flow-item--footer">
            <FooterSection race={race} />
          </div>
        </div>
      </div>
    </div>
  );
}
